{
  "grammar": [
    {
      "pattern": "一 + measure word + noun",
      "structure": ["number", "measure word", "noun"],
      "explanation_en": "Use measure words between numbers and nouns. Common ones: 個 (general), 杯 (cups), 本 (books), 張 (flat objects), 瓶 (bottles), 包 (packages), 盒 (boxes).",
      "title": "Basic Measure Words",
      "meaning": "Measure words are required for counting nouns.",
      "when_to_use": ["When specifying quantity of items", "When ordering or buying items"],
      "when_not_to_use": ["With abstract nouns like 時間 (time)", "With verbs directly"],
      "pragmatic_notes": "In Taiwan, 個 is often used informally for many items, but specific measure words show better language control.",
      "word_order_notes": "Number + measure word + noun (e.g., 一個蘋果).",
      "english_contrast": "English often omits measure words (e.g., 'one apple'), but Chinese requires them.",
      "korean_contrast": "Korean uses counters like '개' (gae) for general items, similar to 個.",
      "negative_examples": [
        {
          "text": "我要一蘋果。",
          "error": "Missing measure word 個 before 蘋果."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我有一書。",
          "error": "Should be 一本書 with measure word 本."
        }
      ],
      "transformation_drills": ["Change '一個茶' to '一杯茶' (cup).", "Change '一個水' to '一瓶水' (bottle)."],
      "production_drills": ["Say 'one cup of coffee' in Chinese.", "Say 'two bottles of water' in Chinese."],
      "common_error_patterns": ["Omitting measure words entirely", "Using wrong measure word (e.g., 一個書 instead of 一本書)"],
      "repair_feedback": {
        "word_order": "Remember: number + measure word + noun.",
        "politeness": "N/A",
        "vocabulary": "Use 個 for general items, 杯 for drinks, 瓶 for bottles, 包 for packages."
      }
    },
    {
      "pattern": "要 + noun + 嗎？ / 要不要 + noun？",
      "structure": ["要", "noun", "嗎", "要不要", "noun"],
      "explanation_en": "Use 要不要 or 要...嗎 to ask if someone wants something. It's a polite way to offer or confirm.",
      "title": "Asking 'Want or Not'",
      "meaning": "Asking if someone wants an item.",
      "when_to_use": ["When offering items like bags, receipts", "When confirming an order"],
      "when_not_to_use": ["For yes/no questions about facts (use 是...嗎)", "For polite requests (use 請 or 不好意思)"],
      "pragmatic_notes": "In Taiwan convenience stores, staff often ask '要不要袋子？' (Do you want a bag?) or '要不要發票？' (Do you want a receipt?).",
      "word_order_notes": "要不要 + noun (e.g., 要不要袋子？) or 要 + noun + 嗎？ (e.g., 要袋子嗎？).",
      "english_contrast": "English uses 'Do you want...?' while Chinese uses 要不要 or 要...嗎.",
      "korean_contrast": "Korean uses '원하세요?' (wonhaseyo?) similar to 要...嗎.",
      "negative_examples": [
        {
          "text": "你要袋子？",
          "error": "Missing 嗎 or 要不要 to form a question."
        }
      ],
      "incorrect_examples": [
        {
          "text": "要不要你袋子？",
          "error": "Word order: 要不要 should come before the noun, not after 你."
        }
      ],
      "transformation_drills": ["Change '要袋子嗎？' to '要不要袋子？'", "Change '要不要發票？' to '要發票嗎？'"],
      "production_drills": ["Ask if someone wants a bag.", "Ask if someone wants a receipt."],
      "common_error_patterns": ["Forgetting 嗎 in 要...嗎 questions", "Placing 要不要 after the noun"],
      "repair_feedback": {
        "word_order": "Put 要不要 before the noun.",
        "politeness": "Using 要不要 is polite enough for convenience stores.",
        "vocabulary": "Use 袋子 for bag, 發票 for receipt."
      }
    },
    {
      "pattern": "這 + measure word + noun / 那 + measure word + noun",
      "structure": ["這/那", "measure word", "noun"],
      "explanation_en": "Use 這 (this) and 那 (that) with measure words to point to specific items. Common: 這個 (this one), 那個 (that one), 這杯 (this cup), 那瓶 (that bottle).",
      "title": "This and That Review",
      "meaning": "Pointing to items using 這 and 那.",
      "when_to_use": ["When selecting items in a store", "When referring to nearby or distant objects"],
      "when_not_to_use": ["Without a measure word (e.g., 這書 is incorrect)", "For abstract concepts (use 這個問題)"],
      "pragmatic_notes": "In Taiwan, 這個 and 那個 are very common in daily speech. Use 這個 for items close to you, 那個 for items farther away.",
      "word_order_notes": "這/那 + measure word + noun (e.g., 這個便當, 那杯咖啡).",
      "english_contrast": "English uses 'this' and 'that' without measure words, but Chinese requires them.",
      "korean_contrast": "Korean uses '이' (i) for this and '그' (geu) for that, followed by counters.",
      "negative_examples": [
        {
          "text": "我要這水。",
          "error": "Missing measure word 瓶 or 杯 before 水."
        }
      ],
      "incorrect_examples": [
        {
          "text": "那書多少錢？",
          "error": "Should be 那本書 with measure word 本."
        }
      ],
      "transformation_drills": ["Change '這個' to '那個' for a distant item.", "Change '這杯茶' to '那杯茶'."],
      "production_drills": ["Say 'this bottle of water' in Chinese.", "Say 'that bag' in Chinese."],
      "common_error_patterns": ["Omitting measure words after 這/那", "Using 這/那 with verbs instead of nouns"],
      "repair_feedback": {
        "word_order": "Always use 這/那 + measure word + noun.",
        "politeness": "N/A",
        "vocabulary": "Use 個 for general, 杯 for cups, 瓶 for bottles, 本 for books, 張 for flat items."
      }
    }
  ]
}
